class PressureVesselControllerFirmwareTests(unittest.TestCase):
    def wait_for_boot_state(self, session: FirmwareSession) -> list[str]:
        return session.read_until(lambda line: line == "DBG STATE SAFE_VENT", timeout_s=3.0)

    def assert_safe_vent_bundle(self, lines: list[str]) -> None:
        self.assertIn("ACT COMPRESSOR OFF", lines)
        self.assertIn("ACT VENT OPEN", lines)
        self.assertNotIn("ACT COMPRESSOR ON", lines)

    def assert_actuator_bundle(self, lines: list[str], compressor_on: bool, vent_open: bool, state_line: str) -> None:
        expected_compressor = f"ACT COMPRESSOR {'ON' if compressor_on else 'OFF'}"
        expected_vent = f"ACT VENT {'OPEN' if vent_open else 'CLOSED'}"
        self.assertIn(expected_compressor, lines)
        self.assertIn(expected_vent, lines)
        self.assertIn(state_line, lines)
        self.assertFalse(compressor_on and vent_open, "controller commanded compressor on with vent open")

